console.log('vnToHangul script loaded');

/* =====================
   GLOBAL TOGGLE STATE
===================== */
let greekEnabled = localStorage.getItem('greekEnabled') !== 'false';

/* =====================
   DEBOUNCE
===================== */
function debounce(func, delay) {
    let timeoutId;
    return function (...args) {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => func.apply(this, args), delay);
    };
}

/* =====================
   FORBIDDEN STRINGS
===================== */
const forbiddenStrings = ['密码', '@', '#', '/'];

function shouldSkip(element) {
    const text = element.textContent;
    return forbiddenStrings.some(s => text.includes(s));
}

/* =====================
   TRANSLATE / RESTORE
===================== */
function translateTextNodes(element, translateFn, reverse = false) {
    if (element.classList && element.classList.contains('CodeBlock')) return;

    for (let node of element.childNodes) {
        if (node.nodeType === Node.TEXT_NODE) {
            if (!reverse) {
                if (!node.__latinOriginal) {
                    node.__latinOriginal = node.textContent;
                }
                node.textContent = translateFn(node.textContent);
            } else {
                if (node.__latinOriginal) {
                    node.textContent = node.__latinOriginal;
                }
            }
        } else if (node.nodeType === Node.ELEMENT_NODE) {
            translateTextNodes(node, translateFn, reverse);
        }
    }
}

function restoreLatin(el) {
    translateTextNodes(el, null, true);
    el.removeAttribute('data-translated');
}

/* =====================
   PROCESS MESSAGE
===================== */
function processMessageContent(el) {
    if (!greekEnabled) return;
    if (el.getAttribute('data-translated') === 'true') return;
    if (shouldSkip(el)) return;

    translateTextNodes(el, vnToHangul);
    el.setAttribute('data-translated', 'true');
}



/* =====================
   VIETNAMESE → CYRILLIC
===================== */

// 1. Remove Vietnamese tone marks (but keep base letters like â, ê, ô, ă, ơ, ư)
function normalizeVietnamese(str) {
    return str
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "") // remove tone marks
        .replace(/đ/g, "d")
        .replace(/Đ/g, "D");
}



function vnToHangul(text) {
    return text
        // ===== digraphs first =====
        .replace(/ngh/gi, "ㅇ")
        .replace(/ng/gi,  "ㅇ")
        .replace(/nh/gi,  "ᄔ")
        .replace(/ph/gi,  "ㅍ")
        .replace(/kh/gi,  "ㅋ")
        .replace(/th/gi,  "ㅌ")
        .replace(/ch/gi,  "ㅊ")
        .replace(/tr/gi,  "ㅈ")
        .replace(/gi/gi,  "ㅉ")
        .replace(/qu/gi,  "ㄲㅜ")

        // ===== single letters =====
        .split("")
        .map(c => vnHangulMap[c] || c)
        .join("");
}

const vnHangulMap = {
    // vowels
    "a":"ㅏ","ă":"ㅑ","â":"ㅕ","e":"ㅐ","ê":"ㅔ","i":"ㅣ",
    "o":"ㅛ","ô":"ㅗ","ơ":"ㅓ","u":"ㅜ","ư":"ㅡ","y":"ㅣ",
    "A":"ㅏ","Ă":"ㅑ","Â":"ㅕ","E":"ㅐ","Ê":"ㅔ","I":"ㅣ",
    "O":"ㅛ","Ô":"ㅗ","Ơ":"ㅓ","U":"ㅜ","Ư":"ㅡ","Y":"ㅣ",

    // consonants
    "b":"ㅃ","c":"ㄲ","d":"ㅆ","đ":"ㄸ","g":"ㄱ","h":"ㅎ",
    "k":"ㄲ","l":"ㄹ","m":"ㅁ","n":"ㄴ","p":"ㅂ","q":"ㄱ",
    "r":"ㄹ","s":"ㅅ","t":"ㄷ","v":"ㅂ","x":"ㅅ",

    "B":"ㅃ","C":"ㄲ","D":"ㅆ","Đ":"ㄸ","G":"ㄱ","H":"ㅎ",
    "K":"ㄲ","L":"ㄹ","M":"ㅁ","N":"ㄴ","P":"ㅂ","Q":"ㄱ",
    "R":"ㄹ","S":"ㅅ","T":"ㄷ","V":"ㅂ","X":"ㅅ"
};



/* =====================
   INITIAL RUN
===================== */
document.addEventListener('DOMContentLoaded', () => {
    console.log('Processing existing messages');
    if (greekEnabled) {
        document
            .querySelectorAll('.message-content, .message')
            .forEach(processMessageContent);
    }
});

/* =====================
   MUTATION OBSERVER
===================== */
const debouncedConvert = debounce(() => {
    if (!greekEnabled) return;
    document.querySelectorAll('div').forEach(processMessageContent);
}, 500);

const observer = new MutationObserver(mutations => {
    for (const mutation of mutations) {
        if (mutation.type === 'childList') {
            for (const node of mutation.addedNodes) {
                if (node.nodeType === Node.ELEMENT_NODE) {
                    if (node.matches('.message-content, .message')) {
                        processMessageContent(node);
                    } else {
                        node
                            .querySelectorAll?.('.message-content, .message')
                            .forEach(processMessageContent);
                    }
                }
            }
            debouncedConvert();
        }
    }
});

document.addEventListener('DOMContentLoaded', () => {
    observer.observe(document.body, { childList: true, subtree: true });
});

/* =====================
   TOGGLE BUTTON
===================== */
document.addEventListener('DOMContentLoaded', () => {
    const btn = document.createElement('button');
    btn.textContent = greekEnabled ? '🅻 Latin' : '한 Hangul';

    Object.assign(btn.style, {
        position: 'fixed',
        bottom: '16px',
        right: '16px',
        zIndex: 99999,
        padding: '8px 12px',
        background: '#222',
        color: '#fff',
        border: 'none',
        borderRadius: '6px',
        cursor: 'pointer',
        fontSize: '13px'
    });

    btn.onclick = () => {
        greekEnabled = !greekEnabled;
        localStorage.setItem('greekEnabled', greekEnabled);

        if (!greekEnabled) {
            btn.textContent = '한 Hangul';
            document
                .querySelectorAll('[data-translated="true"]')
                .forEach(restoreLatin);
        } else {
            btn.textContent = '🅻 Latin';
            document
                .querySelectorAll('.message-content, .message')
                .forEach(processMessageContent);
        }
    };

    document.body.appendChild(btn);

    function updateFullscreenVisibility() {
      if (document.fullscreenElement) {
        btn.style.display = "none";
      } else {
        btn.style.display = "flex";
      }
    }

    // Modern browsers
    document.addEventListener("fullscreenchange", updateFullscreenVisibility);

    // Safari fallback
    document.addEventListener("webkitfullscreenchange", updateFullscreenVisibility);

    // Initial check (important)
    updateFullscreenVisibility();
});

/* =====================
   KEYBOARD SHORTCUT
   Alt + L
===================== */
document.addEventListener('keydown', e => {
    if (e.altKey && e.code === 'KeyL') {
        e.preventDefault();
        document.querySelector('button')?.click();
    }
});

