/* =====================
   CORE STATE
===================== */
let currentLang = localStorage.getItem('vnt_lang') || 'latin';
let uiPosition = localStorage.getItem('vnt_pos') || 'bottom-right';

/* =====================
   TRANSLATION ENGINE
===================== */
function translate(text) {
    if (currentLang === 'latin') return text;
    const config = SCRIPTS_DATA[currentLang];
    if (!config) return text;

    let result = text.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

    if (config.digraphs) {
        config.digraphs.forEach(([regex, replacement]) => {
            result = result.replace(regex, replacement);
        });
    }

    return result.split("").map(c => {
        const lookup = config.hasCase ? c : c.toLowerCase();
        return config.map[lookup] || c;
    }).join("");
}

function processNode(el) {
    if (currentLang === 'latin') return;
    if (el.getAttribute?.('data-vnt-translated') === currentLang) return;
    
    const skipTags = ['SCRIPT', 'STYLE', 'CODE', 'PRE', 'TEXTAREA'];
    if (el.classList?.contains('CodeBlock') || skipTags.includes(el.tagName)) return;

    for (let node of el.childNodes) {
        if (node.nodeType === Node.TEXT_NODE) {
            if (!node.__vnt_original) node.__vnt_original = node.textContent;
            node.textContent = translate(node.__vnt_original);
        } else if (node.nodeType === Node.ELEMENT_NODE) {
            processNode(node);
        }
    }
    el.setAttribute?.('data-vnt-translated', currentLang);
}

function restoreAll() {
    document.querySelectorAll('[data-vnt-translated]').forEach(el => {
        el.removeAttribute('data-vnt-translated');
        for (let node of el.childNodes) {
            if (node.nodeType === Node.TEXT_NODE && node.__vnt_original) {
                node.textContent = node.__vnt_original;
            }
        }
    });
}

/* =====================
   UI CONSTRUCTION
===================== */
function createUI() {
    if (document.getElementById('vnt-ui-container')) return;

    const container = document.createElement('div');
    container.id = 'vnt-ui-container';
    
    const select = document.createElement('select');
    
    // Add Latin Option
    const optLatin = document.createElement('option');
    optLatin.value = 'latin';
    optLatin.textContent = '🅻  Latin';
    if (currentLang === 'latin') optLatin.selected = true;
    select.appendChild(optLatin);

    // Add Language Options with stylized symbols
    for (const [key, data] of Object.entries(SCRIPTS_DATA)) {
        const opt = document.createElement('option');
        opt.value = key;
        // Using a space-padded badge look in the text
        opt.textContent = `[ ${data.symbol} ]  ${data.label}`;
        if (currentLang === key) opt.selected = true;
        select.appendChild(opt);
    }

    const moveBtn = document.createElement('button');
    moveBtn.textContent = '⤢';
    moveBtn.title = "Switch Corner";

    // --- CSS STYLING ---
    Object.assign(container.style, {
        position: 'fixed', 
        zIndex: '2147483647', 
        display: 'flex', 
        gap: '10px',
        padding: '8px 12px', 
        background: 'rgba(34, 34, 34, 0.95)', 
        backdropFilter: 'blur(4px)',
        borderRadius: '12px', 
        border: '1px solid #555',
        boxShadow: '0 8px 32px rgba(0,0,0,0.5)', 
        alignItems: 'center',
        transition: 'all 0.3s ease'
    });

    Object.assign(select.style, {
        background: '#1a1a1a', 
        color: '#00ffcc', // High contrast neon color for labels
        border: '1px solid #444', 
        borderRadius: '6px',
        padding: '4px 8px', 
        cursor: 'pointer', 
        fontSize: '14px',
        fontWeight: 'bold',
        outline: 'none',
        fontFamily: 'monospace' // Monospace helps keep symbols aligned
    });

    Object.assign(moveBtn.style, {
        background: '#444', 
        color: '#fff', 
        border: 'none', 
        borderRadius: '6px',
        width: '30px',
        height: '30px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        cursor: 'pointer', 
        fontSize: '18px',
        transition: 'background 0.2s'
    });

    moveBtn.onmouseover = () => moveBtn.style.background = '#666';
    moveBtn.onmouseout = () => moveBtn.style.background = '#444';
    
    const applyPos = (pos) => {
        container.style.top = pos.includes('top') ? '20px' : 'auto';
        container.style.bottom = pos.includes('bottom') ? '20px' : 'auto';
        container.style.right = '20px';
        uiPosition = pos;
        localStorage.setItem('vnt_pos', pos);
    };

    applyPos(uiPosition);

    select.onchange = (e) => {
        currentLang = e.target.value;
        localStorage.setItem('vnt_lang', currentLang);
        restoreAll();
        if (currentLang !== 'latin') processNode(document.body);
    };

    moveBtn.onclick = () => applyPos(uiPosition === 'bottom-right' ? 'top-right' : 'bottom-right');

    container.appendChild(select);
    container.appendChild(moveBtn);
    document.body.appendChild(container);
}

/* =====================
   INITIALIZATION
===================== */
const observer = new MutationObserver(mutations => {
    if (currentLang === 'latin') return;
    for (const mutation of mutations) {
        mutation.addedNodes.forEach(node => {
            if (node.nodeType === Node.ELEMENT_NODE) processNode(node);
        });
    }
});

function init() {
    createUI();
    if (currentLang !== 'latin') processNode(document.body);
    observer.observe(document.body, { childList: true, subtree: true });
}

if (document.readyState === 'loading') {
    window.addEventListener('DOMContentLoaded', init);
} else {
    init();
}

// Shortcut: Alt + L to reset to Latin
document.addEventListener('keydown', e => {
    if (e.altKey && e.code === 'KeyL') {
        const sel = document.querySelector('#vnt-ui-container select');
        if (sel) { sel.value = 'latin'; sel.dispatchEvent(new Event('change')); }
    }
});

