function vnToDevanagari(text) {
    // 1. Convert the whole string to lowercase for easier matching
    // 2. Or, handle it character by character to preserve visual structure
    return text
        // Handle digraphs first (case-insensitive flag 'i')
        .replace(/ngh/gi, "ङ")
        .replace(/ng/gi,  "ङ")
        .replace(/nh/gi,  "ञ")
        .replace(/ph/gi,  "फ")
        .replace(/kh/gi,  "ख")
        .replace(/th/gi,  "थ")
        .replace(/ch/gi,  "च")
        .replace(/tr/gi,  "ट")
        .replace(/gi/gi,  "ज")
        .replace(/qu/gi,  "क्व")
        .split("")
        .map(c => {
            const lowerC = c.toLowerCase();
            // Look up the lowercase version in your map
            return vnDevanagariMap[lowerC] || c;
        })
        .join("");
}

